// // This module implements a 16-bit binary counter that decrements from 255 to 0 and then wraps around.
module binary_counter(
    input               clk         ,   
    input               rst_n       ,
    input               enable      ,

    output  reg [7:0]   count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count <= 0;
        end else if (enable) begin
            count <= count + 1;
        end
    end

endmodule
